'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { ResourceClient } = require('../src/resourceClient');

test('one cancelled subscriber does not cancel another subscriber', async () => {
  let release;
  const client = new ResourceClient((key, signal) => new Promise((resolve, reject) => {
    release = () => resolve('revision-9');
    signal.addEventListener('abort', () => reject(signal.reason || new Error('aborted')), { once: true });
  }));
  const cancelled = new AbortController();
  const survivor = new AbortController();
  const first = client.get('shared', cancelled.signal);
  const firstRejected = assert.rejects(first);
  const second = client.get('shared', survivor.signal);
  await Promise.resolve();
  cancelled.abort(new Error('view closed'));
  release();
  await firstRejected;
  assert.equal(await second, 'revision-9');
});
